s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')

def lambda_handler(event, context):
    function_name = context.function_name
    request_id = context.request_id
    
    print(f"Function: {function_name}, RequestId: {request_id}")
    
    try:
        operation = event.get('operation', 'process')
        
        if operation == 's3_operation':
            return handle_s3_operation(event)
        elif operation == 'dynamodb_operation':
            return handle_dynamodb_operation(event)
        elif operation == 'sns_operation':
            return handle_sns_operation(event)
        elif operation == 'sqs_operation':
            return handle_sqs_operation(event)
        else:
            return handle_default_operation(event)
            
    except Exception as e:
        print(f"Error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': str(e),
                'requestId': request_id
            })
        }

def handle_s3_operation(event):
    bucket = event.get('bucket', os.environ.get('S3_BUCKET', 'microservices-data'))
    key = event.get('key', f"data/{datetime.now().isoformat()}.json")
    action = event.get('action', 'put')
    
    if action == 'put':
        data = event.get('data', {})
        s3_client.put_object(
            Bucket=bucket,
            Key=key,
            Body=json.dumps(data),
            ContentType='application/json'
        )
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Object uploaded successfully',
                'bucket': bucket,
                'key': key
            })
        }
    elif action == 'get':
        response = s3_client.get_object(Bucket=bucket, Key=key)
        data = json.loads(response['Body'].read())
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Object retrieved successfully',
                'data': data
            })
        }
    elif action == 'delete':
        s3_client.delete_object(Bucket=bucket, Key=key)
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Object deleted successfully',
                'bucket': bucket,
                'key': key
            })
        }

def handle_dynamodb_operation(event):
    table_name = event.get('table', os.environ.get('DYNAMODB_TABLE', 'microservices-data'))
    action = event.get('action', 'put')
    
    table = dynamodb.Table(table_name)
    
    if action == 'put':
        item = event.get('item', {})
        item['timestamp'] = datetime.now().isoformat()
        table.put_item(Item=item)
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Item stored successfully',
                'table': table_name
            })
        }
    elif action == 'get':
        key = event.get('key', {})
        response = table.get_item(Key=key)
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Item retrieved successfully',
                'item': response.get('Item', {})
            }, default=str)
        }
    elif action == 'query':
        key_condition = event.get('keyCondition', {})
        response = table.query(
            KeyConditionExpression=key_condition.get('expression'),
            ExpressionAttributeValues=key_condition.get('values', {})
        )
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Query executed successfully',
                'items': response.get('Items', []),
                'count': response.get('Count', 0)
            }, default=str)
        }

def handle_sns_operation(event):
    topic_arn = event.get('topicArn', os.environ.get('SNS_TOPIC_ARN', ''))
    action = event.get('action', 'publish')
    
    if action == 'publish':
        message = event.get('message', {})
        subject = event.get('subject', 'Microservice Notification')
        
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=json.dumps(message),
            Subject=subject
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message published successfully',
                'messageId': response['MessageId']
            })
        }

def handle_sqs_operation(event):
    queue_url = event.get('queueUrl', os.environ.get('SQS_QUEUE_URL', ''))
    action = event.get('action', 'send')
    
    if action == 'send':
        message = event.get('message', {})
        
        response = sqs_client.send_message(
            QueueUrl=queue_url,
            MessageBody=json.dumps(message),
            MessageAttributes={
                'Timestamp': {
                    'StringValue': datetime.now().isoformat(),
                    'DataType': 'String'
                }
            }
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Message sent successfully',
                'messageId': response['MessageId']
            })
        }
    elif action == 'receive':
        max_messages = event.get('maxMessages', 1)
        
        response = sqs_client.receive_message(
            QueueUrl=queue_url,
            MaxNumberOfMessages=max_messages,
            WaitTimeSeconds=event.get('waitTime', 0)
        )
        
        messages = response.get('Messages', [])
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Messages received successfully',
                'count': len(messages),
                'messages': messages
            })
        }

def handle_default_operation(event):
    return {
        'statusCode': 200,
        'body': json.dumps({
            'message': 'Lambda function executed successfully',
            'event': event,
            'timestamp': datetime.now().isoformat()
        })
    }